// Mission Bow and Arrow Icon - Inline SVG with transparent background and outer rings like Speed
export const MissionRocketIcon = ({ className }: { className?: string }) => {
  return (
    <div
      className={className}
      style={{
        position: "relative",
        width: "100%",
        height: "100%",
        display: "inline-flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      {/* Outer rings SVG - same positioning as Speed */}
      <svg
        viewBox="0 0 200 200"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        style={{
          position: "absolute",
          width: "100%",
          height: "100%",
          top: 0,
          left: 0,
          zIndex: 0,
        }}
      >
        {/* Outer glow circles - same as Speed */}
        <circle
          cx="100"
          cy="100"
          r="90"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeOpacity="0.1"
          fill="none"
        />
        <circle
          cx="100"
          cy="100"
          r="85"
          stroke="currentColor"
          strokeWidth="1"
          strokeOpacity="0.15"
          fill="none"
        />

        {/* Center circle with border */}
        <circle
          cx="100"
          cy="100"
          r="75"
          stroke="currentColor"
          strokeWidth="0.75"
          strokeOpacity="0.1"
          fill="none"
        />
      </svg>

      {/* Bow and Arrow icon - Using SVG without white background, inverted colors (white bow/arrow) */}
      {/* Match Speed's structure - same size as container */}
      {/* eslint-disable-next-line @next/next/no-img-element -- styled local SVG with filter */}
      <img
        src="/bow-and-arrow.svg"
        alt="Bow and Arrow"
        className={className}
        style={{
          width: "85%",
          height: "85%",
          objectFit: "contain",
          position: "relative",
          zIndex: 1,
          // Invert colors: dark bow/arrow becomes white
          filter: "invert(1) brightness(1.2)",
          // Match Speed icon sizing
          display: "block",
        }}
      />
    </div>
  );
};

